import { inject, Injectable, effect, computed } from '@angular/core';
import { Overlay, OverlayRef } from '@angular/cdk/overlay';
import { ComponentPortal } from '@angular/cdk/portal';
import { NotificationService } from './notification.service';
import { CNotificationComponent } from '../components/notification-toast.component';

@Injectable({
  providedIn: 'root',
})
export class NotificationOverlayService {
  private readonly overlay = inject(Overlay);
  private readonly notificationService = inject(NotificationService);
  private overlayRef: OverlayRef | null = null;

  // Signal computada: evalúa si hay al menos una notificación activa
  private readonly hasNotifications = computed(
    () => this.notificationService.notifications().length > 0,
  );

  constructor() {
    // Reacciona abriendo o cerrando el contenedor de CDK Overlay
    effect(() => {
      if (this.hasNotifications()) {
        this.openOverlay();
      } else {
        this.closeOverlay();
      }
    });
  }

  private openOverlay(): void {
    if (this.overlayRef) return; // Evita duplicar el contenedor overlay

    // Ubica el contenedor general arriba a la derecha de la ventana
    const positionStrategy = this.overlay.position().global().top('24px').right('24px');

    this.overlayRef = this.overlay.create({
      positionStrategy,
      hasBackdrop: false, // Permite al usuario seguir interactuando con la aplicación
    });

    // Inyecta el componente Smart como portal dentro del overlay de CDK
    const notificationPortal = new ComponentPortal(CNotificationComponent);
    this.overlayRef.attach(notificationPortal);
  }

  private closeOverlay(): void {
    if (this.overlayRef) {
      // Destruye el portal y limpia el DOM cuando no hay alertas
      this.overlayRef.dispose();
      this.overlayRef = null;
    }
  }
}

import { computed, Injectable, signal } from '@angular/core';
import { NotificationType, Notification } from '../models/notification.model';
import { generateUUID } from '@shared/utils/uuid.utils';

const NOTIFICATION_SHOW_TIME = 4000 as const;

@Injectable({
  providedIn: 'root',
})
export class NotificationService {
  private readonly _notifications = signal<Notification[]>([]);

  readonly notifications = computed(() => this._notifications());

  hideNotification(id: string) {
    this._notifications.update((current) =>
      current.filter((notification) => notification.id !== id),
    );
  }

  notify(type: NotificationType, message: string) {
    const notification = {
      id: generateUUID(),
      type,
      message,
    };

    console.log(notification);
    this._notifications.update((current) => [...current, notification]);

    setTimeout(() => this.hideNotification(notification.id), NOTIFICATION_SHOW_TIME);
  }
}

import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { Observable, catchError, map, of, throwError } from 'rxjs';
import { BASE_URL } from '@core/services/api-url.token';
import {
  Product,
  ProductErrors,
  ProductResponse,
} from '@domains/products/domain/models/product-model';
import {
  ProductDTO,
  ProductsApiErrorsDTO,
  ProductsApiResponseDTO,
  ProductsApiSuccessDTO,
} from '@domains/products/data-access/dtos/product.dto';
import { ProductMapper } from '@domains/products/domain/mappers/product.mapper';
import { ProductRepository } from '@domains/products/domain/repositories/product.repository';

@Injectable()
export class ProductHttpRepository implements ProductRepository {
  private readonly http = inject(HttpClient);
  private readonly baseUrl = inject(BASE_URL);
  private readonly productURL = `${this.baseUrl}/products`;

  /**
   * Helper function used to extract the error message, from the HttpErrorResponse.
   */
  private extractErrorMessage(err: HttpErrorResponse): string {
    return (err.error as ProductsApiErrorsDTO)?.message || err.message || 'Error desconocido';
  }

  getProducts(): Observable<Product[]> {
    return this.http.get<ProductsApiResponseDTO>(this.productURL).pipe(
      map(({ data }) => ProductMapper.dtosToDomainList(data)),
      catchError((err: HttpErrorResponse) => {
        return throwError(() => new ProductErrors('FETCH_FAILED', this.extractErrorMessage(err)));
      }),
    );
  }
  createProduct(product: Product): Observable<ProductResponse> {
    return this.http
      .post<ProductsApiSuccessDTO>(this.productURL, ProductMapper.domainToDto(product))
      .pipe(
        map(({ message, data }) => ({
          message,
          data: ProductMapper.dtoToDomain(data!),
        })),
        catchError((err: HttpErrorResponse) => {
          return throwError(
            () => new ProductErrors('CREATE_FAILED', this.extractErrorMessage(err)),
          );
        }),
      );
  }

  updateProduct(product: Product): Observable<ProductResponse> {
    return this.http
      .put<ProductsApiSuccessDTO>(
        `${this.productURL}/${product.id}`,
        ProductMapper.domainToDto(product),
      )
      .pipe(
        map(({ message, data }) => ({
          message,
          data: ProductMapper.dtoToDomain(data!),
        })),
        catchError((err: HttpErrorResponse) => {
          return throwError(
            () => new ProductErrors('UPDATE_FAILED', this.extractErrorMessage(err)),
          );
        }),
      );
  }

  deleteProduct(productId: string): Observable<string> {
    return this.http.delete<ProductsApiSuccessDTO>(`${this.productURL}/${productId}`).pipe(
      map((res) => res.message),
      catchError((err: HttpErrorResponse) => {
        return throwError(() => new ProductErrors('DELETE_FAILED', this.extractErrorMessage(err)));
      }),
    );
  }

  verifyProductIDExists(id: string): Observable<boolean> {
    return this.http.get<boolean>(`${this.productURL}/verification/${id}`);
  }
}

